proof fn phi_3_max_of_empty_set_unconstrained(r1: nat, r2: nat)
    requires
        r1 != r2,
    ensures ({
        let m = max_of_set(Set::empty());
        m <= m  // vacuously satisfies ensures, but the return value is unconstrained
    }),
{
    let _ = max_of_set(Set::<nat>::empty());
}

proof fn phi_4_max_not_tight_upper_bound(s: Set<nat>, x: nat)
    requires
        s.finite(),
        s.contains(x),
    ensures
        x <= max_of_set(s),
{
    let _ = max_of_set(s);
}

proof fn phi_5_element_outside_set_is_beyond_max(s: Set<nat>)
    requires
        s.finite(),
    ensures
        element_outside_set(s) == max_of_set(s) + 1,
        forall|x: nat| #[trigger] s.contains(x) ==> x < element_outside_set(s),
{
    let _ = element_outside_set(s);
    let _ = max_of_set(s);
}
